mapper.select:
select d.id, d.dept_name as deptName, d.tel, d.email, d.`desc`, count(u.id) as emp from tb_dept d left join tb_user u on d.id = u.dept_id and u.status = 1
and d.dept_name like concat('%',#{deptName},'%')
group by d.id limit #{start}, #{length}

mapper.insert:
insert into tb_dept set
    dept_name = #{deptName}

    , tel = #{tel}


    , email = #{email}


    , `desc` = #{desc}

mapper.update:
update tb_dept set
dept_name = #{deptName}

    , tel = #{tel}


    , email = #{email}


    , `desc` = #{desc}

where id = #{id}

mapper.select:
SELECT NOT EXISTS (
    SELECT 1 FROM tb_user u
    WHERE u.dept_id IN

    #{id}

) AS result
